import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { Chamber, Legislator } from '../../core/models';
import { AuthService } from '../../core/services/auth.service';

@Component({
  selector: 'app-legislators-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './legislators-list.component.html',
  styleUrl: './legislators-list.component.css',
})
export class LegislatorsListComponent implements OnInit {
  private auth = inject(AuthService);
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly isEditor = this.auth.isEditor;

  chamber = signal<Chamber | ''>('');
  party = signal('');
  q = signal('');

  loading = signal(false);
  error = signal('');

  // Mock data — mockup_cleaner clears this signal; service_agent wires listLegislators().
  legislators = signal<Legislator[]>([
    { id: 'l1', name: 'Sen. Marcia Holloway', chamber: 'senate', district: 'S-12', party: 'Republican' },
    { id: 'l2', name: 'Rep. David Cho', chamber: 'house', district: 'H-40', party: 'Democrat' },
    { id: 'l3', name: 'Rep. Ana Whitfield', chamber: 'house', district: 'H-08', party: 'Republican' },
    { id: 'l4', name: 'Sen. Grace Tillman', chamber: 'senate', district: 'S-03', party: 'Democrat' },
    { id: 'l5', name: 'Rep. Owen Barnett', chamber: 'house', district: 'H-22', party: 'Republican' },
    { id: 'l6', name: 'Sen. Priya Raman', chamber: 'senate', district: 'S-19', party: 'Democrat' },
    { id: 'l7', name: 'Rep. Lucas Ferrer', chamber: 'house', district: 'H-51', party: 'Independent' },
    { id: 'l8', name: 'Sen. Karl Osborne', chamber: 'senate', district: 'S-07', party: 'Republican' },
  ]);

  readonly parties = computed(() =>
    Array.from(new Set(this.legislators().map((l) => l.party))).sort(),
  );

  readonly filtered = computed(() => {
    const chamber = this.chamber();
    const party = this.party();
    const q = this.q().trim().toLowerCase();
    return this.legislators().filter((l) => {
      if (chamber && l.chamber !== chamber) return false;
      if (party && l.party !== party) return false;
      if (q && !`${l.name} ${l.district}`.toLowerCase().includes(q)) return false;
      return true;
    });
  });

  ngOnInit(): void {
    const p = this.route.snapshot.queryParamMap;
    this.chamber.set((p.get('chamber') as Chamber) ?? '');
    this.party.set(p.get('party') ?? '');
    this.q.set(p.get('q') ?? '');
  }

  private syncParams(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: {
        chamber: this.chamber() || null,
        party: this.party() || null,
        q: this.q() || null,
      },
      queryParamsHandling: 'merge',
      replaceUrl: true,
    });
  }

  setChamber(v: string): void {
    this.chamber.set(v as Chamber | '');
    this.syncParams();
  }
  setParty(v: string): void {
    this.party.set(v);
    this.syncParams();
  }
  setQuery(v: string): void {
    this.q.set(v);
    this.syncParams();
  }

  clearFilters(): void {
    this.chamber.set('');
    this.party.set('');
    this.q.set('');
    this.syncParams();
  }

  readonly hasFilters = computed(() => !!(this.chamber() || this.party() || this.q()));
}
